// Código para nó Code no n8n
// Extrai e parseia o briefing ÚNICO gerado pela IA
const items = $input.all();
const briefings = [];

for (const item of items) {
  try {
    // Tenta acessar o output da IA
    let rawOutput = item.json.output || item.json.text || item.json;

    // Se for string, faz o parse
    if (typeof rawOutput === 'string') {
      // Remove possíveis prefixos e markdown
      rawOutput = rawOutput
        .replace(/```json\n?/g, '')    // Remove markdown
        .replace(/```\n?/g, '')
        .trim();

      // Parse do JSON
      const parsed = JSON.parse(rawOutput);

      // Adiciona o briefing
      briefings.push(parsed);
    } 
    // Se já for objeto
    else if (typeof rawOutput === 'object' && !Array.isArray(rawOutput)) {
      briefings.push(rawOutput);
    }

  } catch (error) {
    console.error('Erro ao processar item:', error.message);
    console.error('Raw output:', item.json.output || item.json.text || item.json);
    // Continua processando outros items mesmo se um falhar
  }
}

// Valida se temos briefings
if (briefings.length === 0) {
  throw new Error('Nenhum briefing foi extraído. Verifique o formato da resposta da IA.');
}

// Formata data e hora no horário de São Paulo (America/Sao_Paulo)
const agora = new Date();
const dataHoraSP = agora.toLocaleString('pt-BR', { 
  timeZone: 'America/Sao_Paulo',
  day: '2-digit',
  month: '2-digit',
  year: 'numeric',
  hour: '2-digit',
  minute: '2-digit',
  hour12: false
});

// Formata para o padrão: dia/mes/ano hora:minuto
const [data, hora] = dataHoraSP.split(', ');
const dataHoraFormatada = `${data} ${hora}`;

// Retorna cada briefing como um item separado com validação
return briefings.map((briefing, index) => {
  // Validação básica
  if (!briefing.titulo) {
    console.warn('Briefing sem título, pulando...');
    return null;
  }

  if (!briefing.briefing) {
    console.warn('Briefing sem conteúdo, pulando...');
    return null;
  }

  // Gera ID único no formato: post_YYYYMMDD_HHMMSS_MS_INDEX
  // Exemplo: post_20251222_090258_763_11
  const ano = agora.getFullYear();
  const mes = String(agora.getMonth() + 1).padStart(2, '0');
  const dia = String(agora.getDate()).padStart(2, '0');
  const horas = String(agora.getHours()).padStart(2, '0');
  const minutos = String(agora.getMinutes()).padStart(2, '0');
  const segundos = String(agora.getSeconds()).padStart(2, '0');
  const milissegundos = String(agora.getMilliseconds()).padStart(3, '0');

  const id_post = `post_${ano}${mes}${dia}_${horas}${minutos}${segundos}_${milissegundos}_${index + 1}`;

  return {
    json: {
      id_post: id_post,
      titulo: briefing.titulo,
      briefing: briefing.briefing,
      status: briefing.status,
      data_criacao: dataHoraFormatada
    }
  };
}).filter(item => item !== null); // Remove items inválidos
